insert into public.wb_recruitments (id, data) values
  ('job-001', '{"id":"job-001","requestTime":"2026-04-01","department":"吉比特","subDept":"公共部门","projectGroup":"法务组","title":"法务专员（投融资及产品运营方向）","level":"无","salaryRange":"","priority":"P1","businessContact":"周媛媛","hrbp":"","roleTypes":["社招"],"status":"持续招聘","jd":"岗位职责：一、投融资业务合规支持\n1.能够进行投前到投中到投后的全流程投融资项目管理，包括参与投融资项目尽调，梳理项目法律风险，出具尽调意见及风险防控建议。审核、修订投融资相关协议等法律文件，参与商务谈判，保障投融资全流程合规可控；有效进行投后项目管理，识别投后项目风险，并能提供风险解决建议。\n2.能独立统筹投融资项目所产生的纠纷。\n3.整理归档投融资项目相关法律文件。\n二、产品运营业务合规支持\n1.评估产品境内外运营活动的合规性，能够给业务部门规范开展运营工作提供法律建议。\n2.跟踪产品运营相关法律法规及行业监管政策动态，定期梳理政策变化对业务的影响，出具政策解读及落地建议，协助完善公司产品运营合规管理流程。\n3.审核产品代理和运营相关协议或者其他相关法律文件，解答业务法律咨询，处理相关合规纠纷。\n三、根据部门工作要求，完成日常法务工作及上级交办的其他工作。\n任职要求：1.法学专业，本科及以上学历（全日制）。\n2.通过法考，持有法律职业资格证书及英语六级证书。\n3.具备3年以上法律工作经验，拥有互联网公司法务经验以及投融资领域经验优先。\n4.具备独立进行投融资项目管理的经验以及产品运营合规评估的能力。\n5.具有较强的协调、沟通、变通能力、抗压能力，积极主动、逻辑思维缜密；性格踏实稳重，具有较强的责任心与执行力。","reason":"","notes":"","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-002', '{"id":"job-002","requestTime":"2026-03-25","department":"吉比特","subDept":"公共部门","projectGroup":"法务组","title":"法务专员（诉讼维权方向）","level":"无","salaryRange":"","priority":"P2","businessContact":"刘彩灵","hrbp":"","roleTypes":["社招"],"status":"持续招聘","jd":"岗位职责：1.负责公司游戏黑产（包括但不限于私服、外挂）诉讼维权工作，包括但不限于对接公检法通过刑事手段等对案件进行打击；\n2.负责公司日常知识产权维权工作，独立制定并执行诉讼策略，全流程管理知识产权侵权诉讼及不正当竞争等案件；\n3.能独立处理公司其他日常诉讼（包括独立出庭应诉）；\n4.统筹管理律所等外部维权合作机构，把控案件质量与预算；\n5.对内进行知产维权相关法律支持、案例分享及培训；\n6.部门交办的其他法律事务处理。\n任职要求：教育背景：法学专业本科及研究生以上学历（全日制）\n工作经验：3年以上诉讼维权相关经验（互联网或游戏行业优先）\n工作技能：\n1.具备对侵权行为进行识别的敏感度，并进行分析和评估的能力；\n2.熟悉侵权行为证据收集及保全、刑事民事司法全流程；\n3.熟悉知识产权相关法律法规（包括著作权法、商标法、专利法等）、反不正当竞争法、民法典等法律规定；\n4.了解互联网游戏行业的发展趋势、业务模式和常见法律风险，熟悉短视频平台、电商平台、社交媒体等网络环境下的侵权表现形式和维权策略；\n5.具备独立和司法部门沟通配合及工作协调的能力。\n个人素质：\n1.思想成熟，做事沉稳、细致严谨；\n2.自驱力强，工作积极主动，富有较强的责任意识和担当；\n3.具有较强的团队凝聚意识；\n4.具备前瞻性思维和高效统筹工作的魄力；\n5.良好的沟通意识及沟通能力、执行能力、抗压能力、逻辑思维能力和学习能力。","reason":"","notes":"厦门优先","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-003', '{"id":"job-003","requestTime":"2026-03-25","department":"吉比特","subDept":"公共部门","projectGroup":"公共事务组","title":"游戏合规专员","level":"无","salaryRange":"","priority":"P1","businessContact":"曾晓娟","hrbp":"","roleTypes":["社招"],"status":"持续招聘","jd":"【岗位职责】\n1. 游戏版号申请：负责国内游戏版号报审工作，对接游戏研发团队及出版管理部门，游戏审读、协助游戏研发团队完成整改，报审材料准备、进度跟进。\n2. 游戏内容合规审查与培训：负责海内外游戏生命周期内容合规动态审查，跟进及解读海内外游戏相关法律法规、安全规范，为业务部门提供合规咨询，识别风险并推动整改；定期为业务部门开展合规培训与宣传。\n3. 游戏生态治理及舆情风控：敏锐感知国内外舆情动态，解读监管政策，定期开展生态治理专项工作；针对重大/突发风险事件制定内容安全策略，保障内容和产品安全；推动流程及标准持续优化；舆情事故危机处理。\n4. 监管部门及行业协会关系网络搭建：与相关管理部门建立和保持良性工作沟通，及时了解跟踪有关的政策动态。\n5. 创新业务开展及拓展：负责短剧业务备案、内容审核；开拓新业务，协调资源推动新业务落地。\n6. 上级交办的其他工作。\n【任职要求】\n1.本科及以上学历，中文、出版、新闻、法律等相关专业，2年及以上出版/编辑/新闻/合规风控/内容审核/互联网/文化工作经验（条件优秀者可适当放宽），有出版编辑资格证书者优先。\n2. 有较强的责任心，严谨细致、诚恳踏实、积极主动高效。\n3. 热爱游戏行业，熟悉各类游戏玩法、系统逻辑机制等优先。\n4. 有较好的政策敏感性和风险研判能力，党员优先。\n5. 思维逻辑清晰，沟通高效且有条理，具备较好的学习能力、抗压能力和团队协作能力。","reason":"","notes":"杨鹭菁一面——曾晓娟二面——HR面——林慧琴三面——高岩四面\n杨鹭菁习惯自己跟进人选面试流程，我们辅助即可，比如系统安排面试、HR面、谈薪等","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-004', '{"id":"job-004","requestTime":"2026-03-02","department":"吉比特研发","subDept":"技术中心","projectGroup":"技术AI组","title":"AI应用开发工程师","level":"无","salaryRange":"","priority":"P0","businessContact":"梁钰彬","hrbp":"林家琦","roleTypes":["社招"],"status":"持续招聘","jd":"岗位职责：1.负责公司内部工具及业务系统的开发与维护，涵盖服务端、前端及相关系统功能实现。\n2.基于 Python / TypeScript 技术栈进行应用开发，包括 API 接口、Web 页面及系统集成。\n3.参与系统功能设计与实现，能够在 AI 工具辅助下完成跨前后端的开发任务，推动 AI 在日常开发流程中的实践与落地。\n4.推动内部工具及系统的实际落地与应用推广，对使用效果与效率提升结果负责。\n5.持续优化开发流程，提高系统开发效率与工程质量。\n任职要求：1.精通 Python / TypeScript，具备后端或前端开发经验，有开发大型商业软件或网站的经验；\n2.熟悉常见 Web 开发模式，比如服务端开发（如 FastAPI / Django / Node.js 等）、前端开发（如 React / Next.js / Vue 等）。\n3.具备较强的 AI 编程实践经验，对 AI 驱动的开发模式与 Vibe Coding 有深入理解与浓厚兴趣，并能灵活运用于开发实践。\n4.熟悉 PostgreSQL、Redis 等常见数据库或缓存技术者。\n5.了解 Docker、微服务架构或现代 Web 工程体系者。\n6.具备良好的工程习惯、代码规范意识及 Git 协作经验。\n7.具备良好的沟通能力和团队协作精神，能够主动推进问题解决。","reason":"新增需求，侧重 AI 底层算法应用与研发，深入解决算法问题，需搭建 AI 基础算法，加大 AI 在公司落地应用。\n公司 AI 相关产品与应用方向：\n1、现有产品：AI啥啥 贾维斯、丁 cod、新版贾维斯（后两者处于开发阶段）。\n2、推进 AI 员工在公司内部应用：涵盖 PM 管理、内部客服、团队教练、知识库，核心是打通企业内部数据。","notes":"AI应用开发工程师画像梳理","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-005', '{"id":"job-005","requestTime":"2025-12-31","department":"吉比特研发","subDept":"N98/M98","projectGroup":"程序组","title":"UE开发工程师","level":"无","salaryRange":"","priority":"P1","businessContact":"沈予卿","hrbp":"古凯","roleTypes":["社招","校招","实习"],"status":"持续招聘","jd":"岗位职责：\n1、使用UE5，参与玩法与相关模块的开发，以支持游戏核心玩法的设计与迭代；\n2、理解并参与完善设计，实现效果与性能优秀的技术方案，并持续迭代改进，与策划、美术合作推动工作。\n任职要求：\n1、3年及以上Gameplay开发经验，有独立完成模块开发的经验；\n2、掌握C++/Lua/TypeScript编程语言，掌握常用数据结构和算法，有良好的编程能力和习惯；\n3、了解并熟练运用UE的GAS/网络同步/集群怪物AI算法/3C/物理中的一个或多个领域的开发方式及解决方案；\n4、对新技术拥有强烈好奇心，愿意探索并落地到项目中。","reason":"需要补初阶的UE人选（和无界计划同步进行）","notes":"除去还有\nUE客户端>引擎>客户端负责人这三个需求","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-006', '{"id":"job-006","requestTime":"2025-11-28","department":"雷霆运营","subDept":"运营部门","projectGroup":"技术中台","title":"游戏运维工程师","level":"无","salaryRange":"","priority":"P0","businessContact":"陈宝胖","hrbp":"李莎","roleTypes":["社招","校招","实习"],"status":"持续招聘","jd":"岗位职责：\n1、负责对接游戏研发，优化游戏架构，推进游戏上线；\n2、负责游戏服务器搭建、监控、运维、健康管理、故障排查以及紧急响应；\n3、负责游戏服的成本控制；\n4、负责游戏自动化运维工具的开发。\n任职要求：\n1、本科及以上学历，计算机及相关专业，有 2 年以上运维经验；\n2、熟悉 Linux 系统管理维护，熟悉防火墙、VPN、DNS、HTTPS、TCP/IP 等网络技术，对系统性能原理有深刻理解；\n3、具有 K8S、MySQL、Redis、Nginx、MongoDB、Zabbix、Prometheus、Kafka 等常规业务组件丰富的运维经验；\n4、熟悉 shell、Python 脚本编程经验；\n5、有较好的故障定位、排查和分析能力；\n6、有优化意识，细致认真，学习能力，合作精神，抗压能力强。","reason":"目前团队内人力比较紧张，需要招人来缓解压力","notes":"实习生关注学历，需要985211、校招社招统一只看男生\n实习岗位需要在系统上安排评估，评估人：huangyf,chenbp,yanx","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-007', '{"id":"job-007","requestTime":"2025-10-23","department":"吉比特","subDept":"公共部门","projectGroup":"信息技术中心","title":"IT 经理/主管","level":"无","salaryRange":"","priority":"P1","businessContact":"肖志伟","hrbp":"","roleTypes":["社招"],"status":"持续招聘","jd":"一、岗位职责\n1、负责整体 IT 策略的盘点与优化工作，并推动方案的高品质落地；\n2、带领团队提供低\"打断式\"或\"无感知\"的 IT 服务，从技术与机制上保证办公所涉 IT 环境的安全、稳定及流畅；\n3、对各项 IT 开支进行有效的管理，确保开支的投入效果及管理效率；\n4、定期总结复盘 IT 工单，基于用户反馈、工单数据等优化架构与服务流程；\n5、深度研究市场主流 AI 技术与工具，将 AI 能力应用于 IT 全流程，实现 IT 工作智能化提效；搭建 AI 应用权限管理体系，保障 AI 工具安全合规落地；为各部门提供 IT 相关服务支持，结合业务需求输出 AI 应用方案，赋能业务智能化升级。\n二、任职要求\n1、本科及以上学历；\n2、熟悉主流的企业基础 IT 设施，熟悉网络、服务器等模块工作内容及核心管理要点；\n3、具备技术钻研精神，善于追根究底，注重实效；\n4、有很强的责任感、担当，在职责边界模糊时能主动担当，推动需求落地与问题闭环；\n5、具备强烈的服务意识，能够从用户视角出发推动工作优化；\n6、管理风格务实，能深入一线发现问题、优化流程，关注团队成长，能够激发并带动团队成员共同进步；\n7、对市场上的 AI 能力有系统、深入的了解，具备将 AI 技术应用于 IT 工作、实现提效提质的实战经验，熟悉 AI 应用的权限管理与数据安全要求，能带领团队落地 AI 相关项目。","reason":"离职替补，目前团队内新加入了一个IT工程师，需要看下融入情况，来决定要不要继续招主管","notes":"画像沟通\n一、岗位信息\nIT经理/主管，base深圳（业务集中，研发 + 发行场景复杂）\n二、画像偏好（特质能力要求>专业能力）\n本科及以上学历（优先优质院校背景），40 周岁以下；\n具备扎实的网络、服务器、操作系统相关知识与实操经验，能独立解决核心 IT 运维问题；\n具有技术钻研精神，遇到问题善于追根究底，注重实际的成效，不浮于表面；\n有较强的服务与沟通意识，在边界不明确的工作中主动担当，推进需求落地；\n以用户视角优化工作，基于用户真正的需要来工作；\n管理风格接地气，能下场基于实际工作中，发现问题，优化服务流程与技术方案，同时能带动团队共同成长。\n（3456是筛选项，是目前整体提升IT团队工作现状的关键）\n简历要求：逻辑严谨、重点突出，清晰呈现过往工作成果与技术能力。\n三、面试流程\n简历筛选：xiaozw，目前先暂定单独私聊发给他简历；\n一面：xiaozw。","profile":"","process":[],"candidates":[]}'::jsonb),
  ('job-008', '{"id":"job-008","requestTime":"2025-10-01","department":"雷霆运营","subDept":"运营部门","projectGroup":"客服部","title":"VIP客服专员","level":"无","salaryRange":"","priority":"P1","businessContact":"陈坤","hrbp":"王依依","roleTypes":["社招","校招","实习"],"status":"持续招聘","jd":"岗位职责：\n1、通过热线/在线客服系统，以语言/文字接待来访月用户，在用户对项目玩法设计产生认知偏差、产品体验历程环节发生不完美时，及时介入做认知纠偏与问题解决；\n2、分析用户反馈问题，及时反馈异常问题，推动异常修复，降低用户体验历程发生不完美情况，提升公测阶段项目产品口碑；\n3、整理玩家的建议反馈，总结玩家关注的重点内容及反馈量，分析产出舆论汇总和优化建议，助力产品调优；\n4、深度维系付费及高潜力用户，除了以更高专业度和热诚服务用户外，应更贴近用户，收集用户声音向后推动，为用户谋求更好的体验。\n任职要求：\n1、具备一定的服务创造力，能在工作过程中不断拓宽服务内容；\n2、适应高强度重复性工作以及轮班制度，可接受996、997加班；\n3、打字要求：95以上字/分钟，文字思路清晰；\n4、诚实守信，具备一定的服务意识，愿意深耕【服务】领域；\n5、具备一定的共情力，重视用户反馈，积极寻求用户问题解决方法；\n6、为保障服务质量，人选本身需要对手游有一定的操作基础且感兴趣；\n7、有游戏Vip客服经验优先考虑。","reason":"随着挖宝目前的用户数增加，目前VIP用户的日均咨询量已接近问道手游VIP的日均量级，急招5个人来支撑挖宝的业务+其他项目的支持","notes":"九牧之野-产品运营岗位招聘信息-舒逸豪\n到翟哥的面试需要写一个类似的画像文档","profile":"","process":[],"candidates":[]}'::jsonb);
